// src/components/shared/SubTaskList.jsx
import { useState } from "react";
import { taskAPI } from "../../utils/api";
import { StatusBadge } from "./index.jsx";
import SubTaskModal from "./SubTaskModal.jsx";
import { formatMinutes, statusSelectClass } from "../../utils/helpers";

export default function SubTaskList({ task, currentUser, onTaskUpdated }) {
  const [expanded,      setExpanded]      = useState(false);
  const [showModal,     setShowModal]     = useState(false);
  const [editSubTask,   setEditSubTask]   = useState(null);
  const [saving,        setSaving]        = useState(false);

  const subTasks = task.subTasks || [];

  const handleSave = async (form) => {
    setSaving(true);
    try {
      if (editSubTask) {
        const d = await taskAPI.updateSubTask(task._id || task.id, editSubTask._id, form);
        onTaskUpdated(d.task);
      } else {
        const d = await taskAPI.createSubTask(task._id || task.id, form);
        onTaskUpdated(d.task);
      }
      setShowModal(false);
      setEditSubTask(null);
    } catch (e) {
      alert(e.message);
    }
    setSaving(false);
  };

  const handleDelete = async (subId) => {
    if (!window.confirm("Delete this sub-task?")) return;
    try {
      await taskAPI.deleteSubTask(task._id || task.id, subId);
      // Refetch parent
      const d = await taskAPI.getOne(task._id || task.id);
      onTaskUpdated(d.task);
    } catch (e) { alert(e.message); }
  };

  const handleStatusChange = async (subId, status) => {
    try {
      const d = await taskAPI.updateSubTask(task._id || task.id, subId, { status });
      onTaskUpdated(d.task);
    } catch (e) { alert(e.message); }
  };

  const doneCount = subTasks.filter(st => st.status === "Done").length;

  return (
    <div>
      {showModal && (
        <SubTaskModal
          subTask={editSubTask}
          onClose={() => { setShowModal(false); setEditSubTask(null); }}
          onSave={handleSave}
          loading={saving}
        />
      )}

      {/* Expand/collapse trigger */}
      <div
        onClick={() => setExpanded(e => !e)}
        style={{ display:"inline-flex", alignItems:"center", gap:6, cursor:"pointer", userSelect:"none" }}
      >
        <span style={{
          fontSize:11, fontWeight:700, padding:"2px 8px", borderRadius:99,
          background: subTasks.length > 0 ? "#eff6ff" : "#f3f4f6",
          color:      subTasks.length > 0 ? "#1d4ed8" : "#9ca3af",
          border:     `1px solid ${subTasks.length > 0 ? "#bfdbfe" : "#e5e7eb"}`,
        }}>
          {subTasks.length > 0 ? `${doneCount}/${subTasks.length} sub-tasks ${expanded ? "▲" : "▼"}` : "+ sub-tasks"}
        </span>
      </div>

      {expanded && (
        <div style={{ marginTop:10, background:"#f8fafc", borderRadius:10, border:"1px solid #e2e8f0", overflow:"hidden" }}>
          <div style={{ padding:"8px 12px", borderBottom:"1px solid #e2e8f0", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <span style={{ fontSize:11, fontWeight:700, color:"#64748b", textTransform:"uppercase", letterSpacing:".5px" }}>
              Sub-tasks ({subTasks.length})
            </span>
            <button
              onClick={e => { e.stopPropagation(); setEditSubTask(null); setShowModal(true); }}
              style={{ fontSize:11, fontWeight:700, padding:"3px 10px", borderRadius:6, border:"1px solid #2ecc7a", background:"#f0fdf4", color:"#166534", cursor:"pointer", fontFamily:"inherit" }}
            >
              + Add
            </button>
          </div>

          {subTasks.length === 0 ? (
            <div style={{ padding:"14px 12px", textAlign:"center", color:"#9ca3af", fontSize:12 }}>
              No sub-tasks yet. Click "+ Add" to create one.
            </div>
          ) : (
            subTasks.map((st, i) => (
              <div key={st._id || i} style={{ padding:"8px 12px", borderBottom: i < subTasks.length - 1 ? "1px solid #e2e8f0" : "none", display:"flex", alignItems:"center", gap:10, flexWrap:"wrap" }}>
                <span style={{ fontSize:12, color:"#374151", flex:1, minWidth:120 }}>{st.title}</span>
                <select
                  value={st.status}
                  onChange={e => handleStatusChange(st._id, e.target.value)}
                  onClick={e => e.stopPropagation()}
                  className={`status-select ${statusSelectClass(st.status)}`}
                  style={{ fontSize:11, padding:"2px 6px" }}
                >
                  {["To Do","In Progress","Done","Hold"].map(s => <option key={s}>{s}</option>)}
                </select>
                {st.totalMinutes > 0 && (
                  <span style={{ fontSize:11, fontWeight:700, color:"#0a2e1a", background:"#dcfce7", borderRadius:6, padding:"2px 7px" }}>
                    {formatMinutes(st.totalMinutes)}
                  </span>
                )}
                <button
                  onClick={e => { e.stopPropagation(); setEditSubTask(st); setShowModal(true); }}
                  style={{ background:"none", border:"none", cursor:"pointer", fontSize:13, padding:"2px 4px", color:"#6b7280" }}
                  title="Edit"
                >✏️</button>
                <button
                  onClick={e => { e.stopPropagation(); handleDelete(st._id); }}
                  style={{ background:"none", border:"none", cursor:"pointer", fontSize:13, padding:"2px 4px", color:"#ef4444" }}
                  title="Delete"
                >🗑</button>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}
